class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        int diff_count = 0, i = 0, j = 0;
        vector<int> res;
        while (i < m && j < n) {
            if (word1[i] != word2[j]) {
                if (diff_count == 1) {
                    return {};
                }
                diff_count++;
                res.push_back(i);
                i++;
            } else {
                res.push_back(i);
                i++;
                j++;
            }
        }
        if (j != n) {
            return {};
        }
        while (i < m && diff_count < 1) {
            if (word1[i] == word2.back()) {
                res.back() = i;
                diff_count++;
            }
            i++;
        }
        return diff_count == 1 ? res : vector<int>();
    }
};
```
